  const endpointId = String(tc.endpointId ?? '').trim();
  if (!endpointId || !validEndpointIds.has(endpointId.toLowerCase())) throw new Error('testCases[' + i + '].endpointId must match an endpointId from the BE payload.');
  const coveredRequirementIds = asArray(tc.coveredRequirementIds).map(String).map(x => x.trim()).filter(Boolean);
  for (const reqId of coveredRequirementIds) {
    if (!validRequirementIds.has(reqId.toLowerCase())) throw new Error('testCases[' + i + '].coveredRequirementIds contains unknown SRS requirement id ' + reqId + '.');
  }
  const request = tc.request ?? {};
  const expectation = tc.expectation ?? {};
  const expectedStatus = asStatusArray(expectation.expectedStatus);
  if (expectedStatus.length === 0) throw new Error('testCases[' + i + '].expectation.expectedStatus must contain at least one HTTP status code.');
  const requestBody = request.body === undefined || request.body === null ? null : (typeof request.body === 'string' ? request.body : JSON.stringify(request.body));
  return {
    endpointId,
    name: String(tc.name ?? ('Generated test case ' + (i + 1))),
    description: String(tc.description ?? ''),
    testType: String(tc.testType ?? 'HappyPath'),
    priority: String(tc.priority ?? 'Medium'),
    orderIndex: Number.isInteger(Number(tc.orderIndex)) ? Number(tc.orderIndex) : i,
    tags: JSON.stringify(asArray(tc.tags).map(String)),
    request: {
      httpMethod: String(request.httpMethod ?? 'GET'),
      url: String(request.url ?? '/'),
      headers: JSON.stringify(asObject(request.headers)),
      pathParams: JSON.stringify(asObject(request.pathParams)),
      queryParams: JSON.stringify(asObject(request.queryParams)),
      bodyType: String(request.bodyType ?? 'None'),
      body: requestBody,
      timeout: Number(request.timeout ?? 30000)
    },
    expectation: {
      expectedStatus,
      responseSchema: asNullableString(expectation.responseSchema),
      headerChecks: JSON.stringify(asObject(expectation.headerChecks)),
      bodyContains: JSON.stringify(asArray(expectation.bodyContains).map(String)),
      bodyNotContains: JSON.stringify(asArray(expectation.bodyNotContains).map(String)),
      jsonPathChecks: JSON.stringify(asObject(expectation.jsonPathChecks)),
      maxResponseTime: expectation.maxResponseTime ?? null
    },
    variables: asArray(tc.variables),
    coveredRequirementIds,
    traceabilityScore: typeof tc.traceabilityScore === 'number' ? tc.traceabilityScore : null,
    mappingRationale: tc.mappingRationale ? String(tc.mappingRationale) : ''
  };
});
testCases.sort((a, b) => a.orderIndex - b.orderIndex);
testCases.forEach((tc, i) => { tc.orderIndex = i; });
const input = $('Parse Unified Input').first().json;
return [{ json: { callbackUrl: input.callbackUrl, callbackApiKey: input.callbackApiKey, testCases } }];
